export type AnalyticsStatus = "draft";
export type AnalyticsEventKind =
  | "page_view"
  | "opt_in"
  | "checkout_start"
  | "purchase"
  | "order_bump_accept"
  | "upsell_accept"
  | "refund"
  | "subscription_cancel"
  | "product_access_grant"
  | "sequence_started";

export type MetricFormat = "count" | "rate" | "currency";
export type ExperimentStatus =
  | "draft"
  | "assignment_ready"
  | "seeded_routing_ready"
  | "seeded_holdout_ready"
  | "custom_routing_ready";
export type ExperimentRoutingSignal = "utmSource" | "utmCampaign" | "referrerHost";

export type AnalyticsEventDefinition = {
  id: string;
  kind: AnalyticsEventKind;
  title: string;
  sourceRoute: string;
  linkedFeatureIds: string[];
  publicProperties: string[];
  privateDataExcluded: string[];
  aggregation: string;
};

export type MetricDefinition = {
  id: string;
  title: string;
  format: MetricFormat;
  formula: string;
  sourceEventIds: string[];
  caveat: string;
};

export type FunnelStepMetric = {
  id: string;
  stepId: string;
  label: string;
  visitors: number;
  conversions: number;
  conversionRate: number;
  sourceEventIds: string[];
};

export type ExperimentVariant = {
  id: string;
  label: string;
  routingRole: "treatment" | "holdout";
  trafficWeight: number;
  hypothesis: string;
  linkedBlockId: string;
  routedTitle: string;
  routedBody: string;
};

export type ExperimentCustomRoutingRule = {
  id: string;
  label: string;
  status: "active";
  priority: number;
  signal: ExperimentRoutingSignal;
  expectedValue: string;
  variantId: string;
  description: string;
  privacyBoundary: string;
};

export type ExperimentDefinition = {
  id: string;
  title: string;
  status: ExperimentStatus;
  linkedRoute: string;
  assignmentKey: string;
  assignmentRule: string;
  primaryMetricId: string;
  guardrailMetricIds: string[];
  variants: ExperimentVariant[];
  customRoutingRules: ExperimentCustomRoutingRule[];
  writeBoundary: string;
};

export type AnalyticsDashboard = {
  id: string;
  slug: string;
  title: string;
  status: AnalyticsStatus;
  issue: number;
  parentIssue: number;
  sourceDataRoute: string;
  previewRoute: string;
  linkedFunnelRoute: string;
  linkedOfferRoute: string;
  linkedAudienceRoute: string;
  linkedProductRoute: string;
  revisionId: string;
  summary: string;
  events: AnalyticsEventDefinition[];
  metrics: MetricDefinition[];
  funnelStepMetrics: FunnelStepMetric[];
  experiments: ExperimentDefinition[];
  writeBoundary: string;
  validation: string[];
};

